package il.co.dcd.composermapper.model; import java.nio.file.Path; import java.util.*;
public class JavaClassDef { private String packageName; private String simpleName; private String fullyQualifiedName; private Path sourceFile; private final Set<String> imports=new LinkedHashSet<>(); private final Set<String> methodNames=new LinkedHashSet<>(); private final Set<String> setterNames=new LinkedHashSet<>(); private final Set<String> inferredExternalDependencies=new LinkedHashSet<>(); public String getPackageName(){return packageName;} public void setPackageName(String v){this.packageName=v;} public String getSimpleName(){return simpleName;} public void setSimpleName(String v){this.simpleName=v;} public String getFullyQualifiedName(){return fullyQualifiedName;} public void setFullyQualifiedName(String v){this.fullyQualifiedName=v;} public Path getSourceFile(){return sourceFile;} public void setSourceFile(Path p){this.sourceFile=p;} public Set<String> getImports(){return imports;} public Set<String> getMethodNames(){return methodNames;} public Set<String> getSetterNames(){return setterNames;} public Set<String> getInferredExternalDependencies(){return inferredExternalDependencies;} }
